var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一件重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"經過長久的思考，你明白在今後即將面對的命運中，她是不可缺少的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你下定決心。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"做好心理準備後，你將她傳喚到老闆辦公室，他說馬上就會過來。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"종신 계약이요?","JPN":"終身契約ですか？","ENG":"A Lifetime Contract?","TWN":"終身契約？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"대담한 건지 어리석은 건지 모르겠군.","JPN":"大胆なのか、愚かなのか。","ENG":"I don't know if you're bold or foolish.","TWN":"不知是大膽還是愚笨？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_LIGHT_02"},{"id":"L15_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"지저분한 농담이라고 해도, 날 일개 직원으로 취급하는 듯한 네 태도가 썩 마음에 들진 않아.","JPN":"冗談だとしても私を下っ端の社員のように扱うお前の態度が気に食わない。","ENG":"Even if you're just teasing, I don't like that you treat me as if I'm one of your employees.","TWN":"即使是亂七八糟的玩笑，你對待我的態度也不太滿意。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"라고 했을 것 같은 기분이 드네요. 그 여자라면.","JPN":"と返したような気がしますね。彼女なら。","ENG":"That’s what she would have said. I think.","TWN":"如果是她的話，應該會這麼說吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"……어라?","JPN":"……あれ？","ENG":"Huh?","TWN":"……嗯？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"왜 식은 땀을 흘리시죠? 우유라도 한 잔 드릴까요?","JPN":"どうして冷や汗をかいているんですか？　冷たい飲み物でもお出ししましょうか？","ENG":"Why are you sweating? Shall I bring you some milk?","TWN":"為什麼會冒冷汗呢？要來杯牛奶嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"……아시다시피, 전 기억을 잃었어요.","JPN":"……ご存知のとおり、私は記憶を失いました。","ENG":"As you know, I lost my memories.","TWN":"……你也知道，雖然我失去記憶，"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"하지만 이따금 그 여자의 기억이나 감정들이 문득 떠오르기도 하죠.","JPN":"ですが、時々あの女の記憶や感情がふと蘇ることがあります。","ENG":"But sometimes her memories and emotions come up out of nowhere.","TWN":"但有時候又會突然想起有關她的回憶或情緒。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"그 섬뜩한 기억과 감정이 제 것이라고는 도저히 상상할 수는 없지만요.","JPN":"その恐ろしい記憶と感情が私のものだとは到底想像できませんが。","ENG":"I just can’t believe such horrible memories and feelings were actually mine.","TWN":"真無法相信，那些恐怖的回憶或情緒是屬於我的。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"알고 있어요.","JPN":"わかっています。","ENG":"I know.","TWN":"我很清楚…"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"사람들이 저를 보는 시선이 그리 곱지만은 않다는 것쯤.","JPN":"人々が私に向ける視線が厳しいものだということを。","ENG":"I know that people aren’t very fond of me.","TWN":"人們看我的眼光不是很友善。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"하지만 제가 저지른 일이 아니라며 무조건 피하기만 하는 것도 답은 아니겠죠.","JPN":"ですが、私が犯したことではないと言い、ずっと避けていることも正解ではないでしょう。","ENG":"I also know that denying my deeds in the past won’t solve the problem either.","TWN":"但光是否認，一直逃避也不是辦法。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"……좋아요. 계약서를 주세요.","JPN":"……わかりました。契約書をください。","ENG":"Very well. Please give me the contract form.","TWN":"……好，合約給我吧。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"현명하신 사장님이라면 분명 직원에게 올바른 길을 알려 주시겠죠?","JPN":"賢明な社長なら、きっと社員を正しい道に導いてくれるでしょう？","ENG":"You will guide me on the right path, won’t you?","TWN":"如果你是賢能的老闆，應該會指引員工正確的道路吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JAINA_DELTA_NULL_NULL","text":{"KOREA":"아무리 시간이 걸린다고 하더라도, 저는 답을 찾아 내겠어요.","JPN":"いくら時間がかかったとしても、私は答えを見つけ出します。","ENG":"No matter how long it takes, I will find the answer.","TWN":"無論要花多少時間，我都要找出答案。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JAINA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};